var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이게 그 성냥팔이예요?","JPN":"これがあのマッチ売りですか？","ENG":"So this is the infamous Matchmaker?","TWN":"這就是那個賣火柴的？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......에그. 끔찍하게도 타 죽었네. 꿈에 나올까 무섭다.","JPN":"……げっ。燃え方がかなりえぐいですね。夢に出てきそう。","ENG":"Eww. He's charred all over. This is going to give me nightmares.","TWN":"……天啊，死得好慘，我好怕在夢裡見到他。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경찰들 눈을 가리고 교도소에서 왕 노릇 하던 녀석이야.","JPN":"警察を無力にして、刑務所で王みたいな暮らしをしていた奴よ。","ENG":"He used to play king in prison and play the cops for fools.","TWN":"他瞞著員警的監視，在牢獄中稱王。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런 건 업보지.","JPN":"こんなの自業自得。","ENG":"He deserved no less.","TWN":"這都是報應。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"흐음...... 차량이 전소돼서 현장에 단서라고 할 만한 건 거의 안 남았어요.","JPN":"うーん……車両が全焼していて、現場に手がかりと言えるものはほとんど残っていません。","ENG":"Hmm... The car's all burnt up so there's hardly any evidence left on the scene.","TWN":"嗯……車被徹底燒毀了，現場找不到線索。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭣보다 피해자 시신이 부검도 하기 힘든 상태라......","JPN":"なにより被害者の遺体が解剖すらできない状態で……","ENG":"And it's already impossible enough to perform an autopsy on the victim's body...","TWN":"而且被害者的屍體狀態也難以做屍檢……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어디서부터 조사를 해야 할지 막막하네요.","JPN":"どこから調べればいいか……気が遠くなりますね。","ENG":"I don't even know where to begin this investigation.","TWN":"不知道從哪裡著手調查。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님은 뭔가 짚이는 거 없으세요?","JPN":"警視様は何か心当たりはありませんか？","ENG":"You got any hunches, Major?","TWN":"警正大人有沒有什麼想法？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"난 관심 없어. 죽어 마땅한 범죄자가 죽었을 뿐이잖아.","JPN":"興味ない。死んで当然の犯罪者が死んだだけよ。","ENG":"A criminal got what he deserved. I couldn't care less.","TWN":"我沒想法，只是罪該萬死的犯罪者死掉了而已。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"왜 우리가 이 녀석을 죽인 범인을 찾아야 하는 건데?","JPN":"どうして私たちがこいつを殺した犯人を探さなければならないわけ？","ENG":"Why should we even bother finding the killer?","TWN":"我們為什麼要尋找殺了這傢伙的犯人？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하, 그야 범죄자를 죽인 사람도 범죄자니까 그렇겠죠?","JPN":"アハハ、そりゃ犯罪者を殺した人も犯罪者だからでしょう？","ENG":"Hah hah... Because they also committed a crime?","TWN":"啊哈哈，是因為殺了犯罪者的人也是犯罪者吧？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"고등급 카운터가 고작 차가 폭발했다고 이런 꼴이 되진 않아.","JPN":"高ランクカウンターがたかだか車の爆発でこんな姿にはならない。","ENG":"A high-grade Counter doesn't end up like this just because a car exploded.","TWN":"高等級制裁者不會因為車輛爆炸而變成這副模樣。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"게다가 살인사건에서 살해 흔적을 남기지 않았다는 건, 전형적인 카운터 범죄의 케이스지.","JPN":"しかも、殺害の痕跡を残さなかったということは、典型的なカウンター犯罪のケースでしょうね。","ENG":"And the lack of any traces implies that this is a case of typical Counter crime.","TWN":"而且這種殺人不留痕跡的手法，是典型的制裁者犯罪。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범인은 카운터일 가능성이 높아.","JPN":"犯人はカウンターである可能性が高い。","ENG":"It's highly likely that the suspect is a Counter.","TWN":"犯人很可能是制裁者。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오오, 거기까지 생각하셨다니. 경정님도 실력이 꽤 느셨는데요?","JPN":"おお、そこまで考えていたとは。警視様もなかなか成長したものですね。","ENG":"Ooh, you thought that far already? You're getting pretty good at this!","TWN":"噢噢，竟然想到那種地步，警正大人的實力也進步不少哦？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어디까지나 추측이야, 추측! 아닐 수도 있다고!","JPN":"あくまで推測よ、推測！　違うかもしれないし。","ENG":"It's all just a hunch! I could be wrong!","TWN":"只是推測而已，推測！也有可能不是！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"사건 수사가 다 그렇게 시작하는 거죠, 뭘.","JPN":"事件捜査って最初はそういうところから始まるものですよ。","ENG":"Well, all cases start with a hunch after all.","TWN":"調查案件不都是這樣起步的嗎。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};